import { auth, db, signInWithEmailAndPassword, signOut, onAuthStateChanged, collection, doc, setDoc, deleteDoc, onSnapshot, serverTimestamp } from "./core/firebase.js";
import { state } from "./core/state.js";
import { setGameSortDirection, setLastPlayerId } from "./core/storage.js";
import { num, pct, one, sumStats as sumStatsBase, derived, STAT_KEYS, getGameStatsRegistrationType, quarterKey, registeredQuarterNumbers, statHasRegisteredData } from "./calculations/stats-calculations.js";
import { resultMark, resultText, resultWord, resultClass, gameRecord, dateRange, finalScoreFromQuarterScores, quarterScoreKey } from "./calculations/game-calculations.js";
import { filterGamesByDate, filterGamesByMonth } from "./calculations/analysis-calculations.js";
const nav=[['home','ホーム'],['players','選手'],['games','試合'],['stats','分析'],['team','チーム'],['settings','設定']];
const navIcons={home:'home',players:'person',games:'edit_note',stats:'bar_chart',team:'groups',settings:'settings'};
const $=s=>document.querySelector(s); const uid=()=>crypto.randomUUID();
const PLAYER_CATEGORIES=['U15','U14','U13','その他'];
const PLAYER_CATEGORY_RANK={U15:1,U14:2,U13:3,'その他':4};
function playerCategory(p={}){const c=p?.category||p?.grade||'その他';return PLAYER_CATEGORIES.includes(c)?c:'その他'}
function playerNumberValue(value){const m=String(value??'').match(/\d+/);return m?Number(m[0]):999999}
function sortPlayersByCategoryAndNumber(players=[]){return [...players].sort((a,b)=>(PLAYER_CATEGORY_RANK[playerCategory(a)]??4)-(PLAYER_CATEGORY_RANK[playerCategory(b)]??4)||playerNumberValue(a.number)-playerNumberValue(b.number)||String(a.name||'').localeCompare(String(b.name||''),'ja'))}
function normalizeGameDate(value=''){const s=String(value||'').trim();const jp=s.match(/(\d{4})\D+(\d{1,2})\D+(\d{1,2})/);if(jp)return `${jp[1]}-${jp[2].padStart(2,'0')}-${jp[3].padStart(2,'0')}`;const m=s.replaceAll('/','-').match(/^(\d{4})-(\d{1,2})-(\d{1,2})/);return m?`${m[1]}-${m[2].padStart(2,'0')}-${m[3].padStart(2,'0')}`:s}
function sameDateOrderValue(g={}){const same=Number(g.sameDateOrder);if(Number.isFinite(same))return same;const old=Number(g.sortOrder);return Number.isFinite(old)?old:Number.MAX_SAFE_INTEGER}
function createdOrderValue(g={}){if(g.createdAt?.seconds)return Number(g.createdAt.seconds);const t=Date.parse(g.createdAt||g.updatedAt||'');return Number.isFinite(t)?t:0}
function sortGamesByDateAndSameDateOrder(games=[],direction=state.gameSortDirection){const dateDirection=direction==='asc'?1:-1;return [...games].sort((a,b)=>{const da=normalizeGameDate(a.date||a.gameDate),db=normalizeGameDate(b.date||b.gameDate);if(da!==db)return da>db?dateDirection:-dateDirection;const oa=sameDateOrderValue(a),ob=sameDateOrderValue(b);if(oa!==ob)return oa-ob;const ca=createdOrderValue(a),cb=createdOrderValue(b);if(ca!==cb)return ca-cb;return String(a.id||'').localeCompare(String(b.id||''))})}
function toast(t){const el=$('#toast');el.textContent=t;el.classList.add('show');setTimeout(()=>el.classList.remove('show'),1800)}
function navRender(){for(const id of ['pcNav','mobileNav']){const n=$('#'+id);n.innerHTML=nav.map(([k,v])=>`<button class="${state.tab===k?'active':''}" data-tab="${k}"><span class="material-symbols-outlined">${navIcons[k]}</span><span>${v}</span></button>`).join('');n.querySelectorAll('button').forEach(b=>b.onclick=()=>{state.tab=b.dataset.tab;render()})}}
function sync(){onSnapshot(collection(db,'players'),s=>{state.players=sortPlayersByCategoryAndNumber(s.docs.map(d=>({id:d.id,...d.data()}))); if(!state.lastPlayerId&&state.players[0]) state.lastPlayerId=state.players[0].id; render()});onSnapshot(collection(db,'games'),s=>{state.games=sortGamesByDateAndSameDateOrder(s.docs.map(d=>({id:d.id,...d.data()})));render()});onSnapshot(collection(db,'stats'),s=>{state.stats=s.docs.map(d=>({id:d.id,...d.data()}));$('#cloudStatus').textContent='クラウド接続済み';render()})}
onAuthStateChanged(auth,u=>{state.user=u; $('#pcLoginBtn').textContent=u?'ログアウト':'管理者としてログイン'; syncOnce(); render()});let did=false;function syncOnce(){if(!did){did=true;sync()}}
$('#pcLoginBtn').onclick=()=>state.user?logout():loginModal();
function loginModal(){modal(`<h2>ログイン</h2><div class="grid"><label>メール<input id="loginEmail" autocomplete="username" type="email"></label><label>パスワード<input id="loginPass" autocomplete="current-password" type="password"></label><button class="btn" id="doLogin">ログイン</button><button class="btn ghost" id="closeModal">閉じる</button></div>`);$('#doLogin').onclick=async()=>{try{await signInWithEmailAndPassword(auth,$('#loginEmail').value,$('#loginPass').value);closeModal();toast('ログインしました')}catch(e){toast('ログイン失敗')}};$('#closeModal').onclick=closeModal}
async function logout(){await signOut(auth);toast('ログアウトしました')}
function modal(html){document.body.classList.remove('bg-login','bg-input');document.body.classList.add(html.includes('<h2>ログイン</h2>')?'bg-login':'bg-input');$('#modalRoot').innerHTML=`<div class="modal"><div class="card">${html}</div></div>`} function closeModal(){document.body.classList.remove('bg-login','bg-input');$('#modalRoot').innerHTML=''}
function requireLogin(){if(!state.user){toast('ログインが必要です');return false}return true}
function player(){return state.players.find(p=>p.id===state.lastPlayerId)||state.players[0]||null}
function playerStats(pid,items=state.stats){return items.filter(s=>s.playerId===pid&&statHasRegisteredData(s,state.games.find(g=>g.id===s.gameId)))}
function gameStats(gid,pid){return state.stats.find(s=>s.gameId===gid&&s.playerId===pid)}
function sumStats(items){return sumStatsBase(items,state.games)}
function categories(){return [...new Set(state.games.map(g=>g.category).filter(Boolean))]}
function categoryGames(){return state.categoryId?state.games.filter(g=>(g.category||'')===state.categoryId):state.games}
function statsForGame(gameId,pid=''){const game=state.games.find(g=>g.id===gameId);return state.stats.filter(s=>s.gameId===gameId&&(!pid||s.playerId===pid)&&statHasRegisteredData(s,game))}
function statGameIds(pid=''){return new Set(state.stats.filter(s=>(!pid||s.playerId===pid)&&statHasRegisteredData(s,state.games.find(g=>g.id===s.gameId))).map(s=>s.gameId).filter(Boolean))}
function registeredQCountForGame(g,pid=''){const stats=statsForGame(g.id,pid);if(!stats.length)return 0;if(getGameStatsRegistrationType(g)==='game')return num(g.quarters||stats[0]?.quarters||0);const quarters=new Set();stats.forEach(s=>registeredQuarterNumbers(s).forEach(q=>quarters.add(q)));return quarters.size}
function totalQForGames(games=state.games,pid=''){return games.reduce((a,g)=>a+registeredQCountForGame(g,pid),0)}
function gamesWithStats(games=state.games,pid=''){const ids=statGameIds(pid);return games.filter(g=>ids.has(g.id))}
function quarterStatusText(g,pid=''){if(getGameStatsRegistrationType(g)!=='quarter')return '';const stats=statsForGame(g.id,pid);if(!stats.length)return '';const registered=new Set();stats.forEach(s=>registeredQuarterNumbers(s).forEach(q=>registered.add(q)));const all=Array.from({length:Math.max(1,num(g.quarters||4))},(_,i)=>i+1);const done=all.filter(q=>registered.has(q)).map(q=>`${q}Q`).join('/');const missing=all.filter(q=>!registered.has(q)).map(q=>`${q}Q`).join('/');return ` 登録:${done||'-'}${missing?` 未:${missing}`:''}`}
function detailStatsViews(){return state.detailStatsViews||(state.detailStatsViews={})}
function detailStatsView(g){const type=getGameStatsRegistrationType(g);if(type!=='quarter')return 'game';const view=detailStatsViews()[g.id]||'game';const q=Number(String(view).replace('q',''));return view==='game'||(q>=1&&q<=num(g.quarters||4))?view:'game'}
function setDetailStatsView(gameId,view){detailStatsViews()[gameId]=view}
function quarterRegisteredForStat(stat={},q){return registeredQuarterNumbers(stat).includes(num(q))}
function detailStatsViewControl(g,stat={}){const type=getGameStatsRegistrationType(g),current=detailStatsView(g);const qCount=Math.max(1,num(g.quarters||4));const style=type==='quarter'?` style="grid-template-columns:1.3fr repeat(${qCount},minmax(0,1fr))"`:' style="grid-template-columns:minmax(0,1fr)"';const gameBtn=`<button type="button" class="detail-stat-view-btn ${current==='game'?'active':''}" data-detail-game="${g.id}" data-detail-view="game">試合</button>`;if(type!=='quarter')return `<div class="seg detail-stat-view-seg"${style}>${gameBtn}</div>`;const qs=Array.from({length:qCount},(_,i)=>{const q=i+1,view=`q${q}`,saved=quarterRegisteredForStat(stat,q);return `<button type="button" class="detail-stat-view-btn ${current===view?'active':''} ${saved?'saved':'unsaved'}" data-detail-game="${g.id}" data-detail-view="${view}">${q}Q</button>`}).join('');return `<div class="seg detail-stat-view-seg"${style}>${gameBtn}${qs}</div>`}
function statForDetailView(g,stat={}){const view=detailStatsView(g);if(getGameStatsRegistrationType(g)!=='quarter'||view==='game')return stat?.id?[stat]:[];const q=num(view.replace('q','')),qk=quarterKey(q),qData=stat.quarters?.[qk];return stat?.id?[{...stat,quarters:{[qk]:qData}}]:[]}
function detailUnregisteredNotice(g,stat={}){const view=detailStatsView(g);if(getGameStatsRegistrationType(g)!=='quarter'||view==='game')return '';const q=num(view.replace('q',''));return quarterRegisteredForStat(stat,q)?'':`<p class="sub detail-unregistered">${q}Qのスタッツは未登録です</p>`}
function combinedQuarterStat(stats=[]){const quarters={};stats.forEach(s=>registeredQuarterNumbers(s).forEach(q=>quarters[quarterKey(q)]={registered:true}));return {quarters}}
function statsForSelectedGameView(g,items=[]){if(!g||getGameStatsRegistrationType(g)!=='quarter'||detailStatsView(g)==='game')return items;return items.flatMap(s=>statForDetailView(g,s))}
function scoreLine(g){const score=finalScoreFromQuarterScores(g);return `${score.team} - ${score.opponent}`}
function isMobileView(){return window.matchMedia&&window.matchMedia('(max-width:800px)').matches}
function targetGames(){let games=categoryGames();if(state.statsMode==='game') games=games.filter(g=>g.id===state.targetId); if(state.statsMode==='tournament') games=games.filter(g=>g.tournament===state.targetId); if(state.statsMode==='day') games=games.filter(g=>g.date===state.targetId); if(state.statsMode==='month') games=games.filter(g=>(g.date||'').slice(0,7)===state.targetId); if(state.statsMode==='year') games=games.filter(g=>(g.date||'').slice(0,4)===state.targetId); if(state.statsMode==='period') games=games.filter(g=>(!state.periodStart||g.date>=state.periodStart)&&(!state.periodEnd||g.date<=state.periodEnd)); return games}
function gameCard(g,cls='',draggable=false){return `<div class="list-item sortable-item ${cls}" draggable="false" data-game-id="${g.id}" onclick="openGameDetail('${g.id}')"><div class="game-line1"><span>${g.date||''}</span><span>${[g.tournament,g.category].filter(Boolean).join(' / ')}</span></div><div class="game-line2"><span>vs ${g.opponent||''}</span><span>${g.quarters||0}Q${quarterStatusText(g)}　${resultMark(g)} ${scoreLine(g).replace(" - ","-")}</span></div>${draggable&&state.user?'<button type="button" class="sort-handle game-sort-handle" draggable="false" aria-label="並び替え">≡</button>':''}</div>`}
function targetGameList(){if(!['game','tournament','day'].includes(state.statsMode))return '';const games=targetGames();return `<div class="card"><div class="section-title">集計対象試合一覧</div>${games.map(g=>gameCard(g)).join('')||'<p class="sub">対象試合なし</p>'}</div>`}
function numInput(id,value){return `<div class="num-wrap"><input type="number" min="0" id="${id}" value="${num(value)}"><div class="num-steps"><button type="button" data-step-for="${id}" data-delta="1">▲</button><button type="button" data-step-for="${id}" data-delta="-1">▼</button></div></div>`}
function statsGrid(r,per=true){const d=derived(r),g=per?d.games:1;return `<div class="stats-table">
  <div class="stats-row points-row">
    <div class="stats-cell key"><span>POINTS</span><b>${one(d.pts,g)}</b></div>
    <div class="stats-cell made"><span>2P成功</span><b>${one(r.twoPm,g)}</b></div>
    <div class="stats-cell made"><span>3P成功</span><b>${one(r.threePm,g)}</b></div>
    <div class="stats-cell made"><span>FT成功</span><b>${one(r.ftm,g)}</b></div>
  </div>
  <div class="stats-row triple"><div><span>2PA</span><b>${one(r.twoPa,g)}</b></div><div><span>2PM</span><b>${one(r.twoPm,g)}</b></div><div><span>2P%</span><b>${pct(r.twoPm,r.twoPa)}</b></div></div>
  <div class="stats-row triple"><div><span>3PA</span><b>${one(r.threePa,g)}</b></div><div><span>3PM</span><b>${one(r.threePm,g)}</b></div><div><span>3P%</span><b>${pct(r.threePm,r.threePa)}</b></div></div>
  <div class="stats-row triple fg-row"><div><span>FGA</span><b>${one(d.fga,g)}</b></div><div><span>FGM</span><b>${one(d.fgm,g)}</b></div><div><span>FG%</span><b>${pct(d.fgm,d.fga)}</b></div></div>
  <div class="stats-row triple"><div><span>FTA</span><b>${one(r.fta,g)}</b></div><div><span>FTM</span><b>${one(r.ftm,g)}</b></div><div><span>FT%</span><b>${pct(r.ftm,r.fta)}</b></div></div>
  <div class="stats-row dual"><div class="key"><span>AST</span><b>${one(r.ast,g)}</b></div><div class="key"><span>BLK</span><b>${one(r.blk,g)}</b></div></div>
</div>`}
function breakdown(title,total,arr,games){return `<div class="break-card break-count-${arr.length}"><div class="break-total"><span>${title}合計</span><b>${one(total,games)}</b></div>${arr.map(([lab,val])=>`<div class="break-item"><span>${lab}</span><b>${one(val,games)}</b></div>`).join('')}</div>`}
function toBreakdown(total,arr,games){return `<div class="break-card break-count-5 to-break"><div class="break-total"><span>TO合計</span><b>${one(total,games)}</b></div><div class="to-items">${arr.map(([lab,val])=>`<div class="break-item"><span>${lab}</span><b>${one(val,games)}</b></div>`).join('')}</div></div>`}
function allBreakdowns(r,d,per=true){const g=per?d.games:1;return `<div class="card break-wrap">${breakdown('STL',d.stl,[['パスカット',r.passCut],['ドリブルカット',r.dribbleCut],['その他',r.stealOther]],g)}${breakdown('REB',d.reb,[['オフェンス',r.or],['ディフェンス',r.dr]],g)}${toBreakdown(d.to,[['パスミス',r.passMiss],['ドリブルミス',r.dribbleMiss],['キャッチミス',r.catchMiss],['バイオレーション',r.violation],['その他',r.otherTo]],g)}</div>`}
function statVal(v,g,per){return per?one(v,g):String(num(v))}
function analysisBasic(r,per){const d=derived(r),g=per?d.games:1;return `<div class="analysis-basic">${[['PTS（ポイント）',d.pts],['AST（アシスト）',r.ast],['BLK（ブロック）',r.blk],['STL（スティール）',d.stl],['REB（OR+DR）',d.reb],['TO（ターンオーバー）',d.to]].map(([lab,val])=>`<div class="analysis-basic-card"><span>${lab}</span><b>${statVal(val,g,per)}</b></div>`).join('')}</div>`}
function analysisShots(r,per){const d=derived(r),g=per?d.games:1;const names=['2ポイント','3ポイント','フィールドゴール','フリースロー'];const groups=[[names[0],'2PA','2PM','2P%',r.twoPa,r.twoPm,pct(r.twoPm,r.twoPa)],[names[1],'3PA','3PM','3P%',r.threePa,r.threePm,pct(r.threePm,r.threePa)],[names[2],'FGA','FGM','FG%',d.fga,d.fgm,pct(d.fgm,d.fga)],[names[3],'FTA','FTM','FT%',r.fta,r.ftm,pct(r.ftm,r.fta)]];return `<div class="card analysis-shot-card"><div class="section-title">シュート内訳</div><div class="analysis-shot-grid">${groups.map(([title,a,m,p,av,mv,pv])=>`<div class="analysis-shot"><h3>${title}</h3><div class="analysis-shot-values"><div><span>${a}</span><b>${statVal(av,g,per)}</b></div><div><span>${m}</span><b>${statVal(mv,g,per)}</b></div><div class="pct"><span>${p}</span><b>${pv}</b></div></div></div>`).join('')}</div></div>`}
function analysisBreak(title,total,items,g,per,cls){return `<div class="analysis-break"><h3>${title}内訳</h3><div class="analysis-break-values ${cls}">${items.map(([short,long,val])=>`<div><span>${short}</span><span>(${long})</span><b>${statVal(val,g,per)}</b></div>`).join('')}</div><div class="analysis-break-total"><span>合計</span><b>${statVal(total,g,per)}</b></div></div>`}
function analysisToBreakdown(r,d,g,per){const items=[['PM','パスミス',r.passMiss],['DM','ドリブルミス',r.dribbleMiss],['CM','キャッチミス',r.catchMiss],['VIO','バイオレーション',r.violation],['OTH','その他',r.otherTo],['合計','',d.to]];return `<div class="analysis-break analysis-to-break"><h3>TO内訳</h3><div class="analysis-break-values cols6">${items.map(([short,long,val],i)=>`<div class="${i===5?'analysis-total-cell':''}"><span>${short}</span>${long?`<span>(${long})</span>`:''}<b>${statVal(val,g,per)}</b></div>`).join('')}</div></div>`}
function analysisBreakdowns(r,per){const d=derived(r),g=per?d.games:1,dsLabel=isMobileView()?'スティール':'ドリブルスティール';return `<div class="analysis-break-grid">${analysisBreak('STL',d.stl,[['PI','インターセプト',r.passCut],['DS',dsLabel,r.dribbleCut],['OTH','その他',r.stealOther]],g,per,'cols3')}${analysisBreak('REB',d.reb,[['OR','オフェンスリバウンド',r.or],['DR','ディフェンスリバウンド',r.dr]],g,per,'cols2')}${analysisToBreakdown(r,d,g,per)}</div>`}
function analysisGameTable(games){const mobile=isMobileView();return `<div class="analysis-game-list compact">${games.map(g=>{const body=`<div><b>${g.date||''}</b><span>${g.tournament||'大会未登録'}</span></div><div class="analysis-game-scoreline"><span>vs ${g.opponent||''}</span><b class="analysis-game-score">${scoreLine(g)}</b><em class="${resultClass(g)}">${resultWord(g)}</em></div>`;return mobile?`<button type="button" class="analysis-game-item" onclick="openAnalysisGame('${g.id}')">${body}</button>`:`<div class="analysis-game-item">${body}</div>`}).join('')||'<div class="analysis-game-item"><div><b>対象試合なし</b></div></div>'}</div>`}
function homeStatsModeControl(){return `<div class="seg home-stats-mode"><button type="button" class="home-stats-mode-btn ${state.homeStatsMode!=='fourQuarterAverage'?'active':''}" data-home-stats-mode="total">全試合合計</button><button type="button" class="home-stats-mode-btn ${state.homeStatsMode==='fourQuarterAverage'?'active':''}" data-home-stats-mode="fourQuarterAverage">1試合4Q換算平均</button></div>`}
function homeStatsContent(p,pc=false){const items=p?playerStats(p.id):[];const r=sumStats(items),per=state.homeStatsMode==='fourQuarterAverage';const enteredGames=gamesWithStats(state.games,p?.id),totalQ=totalQForGames(enteredGames,p?.id),period=enteredGames.length?dateRange(enteredGames):'未登録';const suffix=per?'（1試合4Q換算）':'（全試合合計）';return `<div class="home-total-card"><div>対象試合数：${enteredGames.length} 試合</div><div>総Q数：${totalQ}Q</div><div>登録期間：${period}</div></div>${homeStatsModeControl()}<button type="button" class="card home-player-card home-player-select" id="homePlayerSelect"><div class="home-player-icon"><span class="material-symbols-outlined">person</span></div><div><div class="home-player-kicker">最後に選択した選手</div><div class="home-player-name">${p?p.name||'選手名未登録':'選手未登録'}</div><div class="home-player-meta">#${p?.number||'-'} <span>|</span> ${p?.position||'-'} ${pc?playerCategory(p):''}</div></div></button><div class="card analysis-info home-stats-card"><div class="analysis-game-basic"><div class="section-title">基本スタッツ <span>${suffix}</span></div>${analysisBasic(r,per)}</div></div>${analysisShots(r,per)}<div class="card analysis-break-card">${analysisBreakdowns(r,per)}</div>`}
function homeMobile(){const p=player();const auth=state.user?`<div class="auth-actions home-auth-actions logout-home-actions"><button class="btn ghost login-home" id="logoutHome">ログアウト</button></div>`:`<div class="auth-actions home-auth-actions"><button class="btn login-home" id="loginHome">管理者としてログイン</button></div>`;return `<div class="home-mobile analysis-screen">${auth}${homeStatsContent(p,false)}</div>`}
function home(){if(isMobileView())return homeMobile();const p=player();const auth=state.user?`<div class="auth-actions home-auth-actions logout-home-actions"><button class="btn ghost login-home" id="logoutHome">ログアウト</button></div>`:`<div class="auth-actions home-auth-actions"><button class="btn login-home" id="loginHome">管理者としてログイン</button></div>`;return `<div class="home-pc analysis-screen">${auth}${homeStatsContent(p,true)}</div>`}
function playersView(){return `<div class="card"><div class="row list-header" style="justify-content:space-between"><h2>選手</h2></div>${state.user?'<div class="mobile-list-action"><button class="btn" id="addPlayerMobile">＋選手登録</button></div>':''}${state.players.map(p=>`<div class="list-item sortable-item player-sort-item" draggable="false" data-player-id="${p.id}"><div class="game-line2">No.${p.number||''} ${p.name||''}</div><div class="sub">${playerCategory(p)} ${p.position||''}</div>${state.user?`<div class="row"><button class="btn small ghost" onclick="editPlayer('${p.id}')">修正</button></div><button type="button" class="sort-handle player-sort-handle" draggable="false" aria-label="並び替え">≡</button>`:''}</div>`).join('')||'<p class="sub">選手データなし</p>'}</div>`}
function gamesView(){const label=state.gameSortDirection==='asc'?'昇順':'降順';const next=state.gameSortDirection==='asc'?'降順':'昇順';return `<div class="card"><div class="row list-header" style="justify-content:space-between"><h2>試合一覧</h2></div>${state.user?'<div class="mobile-list-action"><button class="btn" id="addGameMobile">＋試合登録</button></div>':''}<div class="row game-sort-control"><span class="sub">日付順：${label}</span><button type="button" class="btn small ghost" id="toggleGameSort"> ${next}に切替 </button></div><p class="sub">${state.user?'同じ日付内のみ長押し／ドラッグで並び替えできます':'試合をタップすると詳細を表示します'}</p>${state.games.map((g,i)=>gameCard(g,'game-sort-item',true)).join('')||'<p class="sub">試合データなし</p>'}</div>`}
function statsView(){const p=player();const mobile=isMobileView();if(mobile&&state.statsMode==='year'){state.statsMode='all';state.targetId=''}const games=categoryGames();const modes=[['game','&#x8A66;&#x5408;'],['tournament','&#x5927;&#x4F1A;'],['all','&#x5168;&#x671F;&#x9593;'],['month','&#x6708;'],['day','&#x65E5;'],['period','&#x671F;&#x9593;&#x6307;&#x5B9A;']];let targets=[];const previousTarget=state.targetId;if(state.statsMode==='game')targets=games.map(g=>({id:g.id,label:`${g.date||''} vs ${g.opponent||''}`}));if(state.statsMode==='tournament')targets=[...new Set(games.map(g=>g.tournament).filter(Boolean))].map(x=>({id:x,label:x}));if(state.statsMode==='day')targets=[...new Set(games.map(g=>g.date).filter(Boolean))].map(x=>({id:x,label:x}));if(state.statsMode==='month')targets=[...new Set(games.map(g=>(g.date||'').slice(0,7)).filter(Boolean))].map(x=>({id:x,label:x}));if(state.statsMode==='year')targets=[...new Set(games.map(g=>(g.date||'').slice(0,4)).filter(Boolean))].map(x=>({id:x,label:x}));if(targets.length&&!targets.some(t=>t.id===state.targetId))state.targetId=targets[0].id;if(!targets.length&&!['all','period'].includes(state.statsMode))state.targetId='';if(state.statsMode==='game'&&state.targetId&&state.targetId!==previousTarget)setDetailStatsView(state.targetId,'game');let items=filterItems(p?.id);if(state.statsMode==='game'){const g=state.games.find(x=>x.id===state.targetId);items=statsForSelectedGameView(g,items)}const r=sumStats(items);const per=state.statsMode!=='game';let targetControl='';if(['game','tournament','year'].includes(state.statsMode))targetControl=`<div class="analysis-target-row"><label>対象選択<select id="statTarget">${targets.map(t=>`<option value="${t.id}" ${t.id===state.targetId?'selected':''}>${t.label}</option>`).join('')}</select></label></div>`;if(state.statsMode==='month'){const years=[...new Set(games.map(g=>(g.date||'').slice(0,4)).filter(Boolean))];const y=(state.targetId||targets[0]?.id||'').slice(0,4);const months=[...new Set(games.filter(g=>(g.date||'').slice(0,4)===y).map(g=>(g.date||'').slice(5,7)).filter(Boolean))];const m=(state.targetId||targets[0]?.id||'').slice(5,7)||months[0]||'';targetControl=`<div class="analysis-target-row"><label>年選択<select id="monthYear">${years.map(x=>`<option value="${x}" ${x===y?'selected':''}>${x}</option>`).join('')}</select></label><label>月選択<select id="monthMonth">${months.map(x=>`<option value="${x}" ${x===m?'selected':''}>${x}</option>`).join('')}</select></label></div>`}if(state.statsMode==='day')targetControl=`<div class="analysis-target-row"><label>日付選択<input type="date" id="statTarget" value="${state.targetId||''}"></label></div>`;if(state.statsMode==='period')targetControl=`<div class="analysis-target-row"><label>開始日<input type="date" id="periodStart" value="${state.periodStart||''}"></label><label>終了日<input type="date" id="periodEnd" value="${state.periodEnd||''}"></label></div>`;const catOptions=[...new Set(['U15','U14','U13',...categories()])];const categoryControl=mobile?`<select id="statCategory"><option value="" ${state.categoryId===''?'selected':''}>全カテゴリー</option>${catOptions.map(c=>`<option value="${c}" ${state.categoryId===c?'selected':''}>${c}</option>`).join('')}</select>`:`<div class="seg category-seg">${['U15','U14','U13'].map(c=>`<button type="button" class="cat-btn ${state.categoryId===c?'active':''}" data-category="${c}">${c}</button>`).join('')}</div>`;const filter=`<div class="analysis-title"><h2>分析 <small>ANALYSIS</small></h2></div><div class="card analysis-filter-card"><div class="analysis-filter"><label>対象選手<select id="statPlayer">${state.players.map(x=>`<option value="${x.id}" ${x.id===p?.id?'selected':''}>No.${x.number||''} ${x.name||''}</option>`).join('')}</select></label><div><label>カテゴリー</label>${categoryControl}</div><div class="wide"><label>集計条件を選択</label><div class="seg mode-seg">${modes.map(([id,label])=>`<button type="button" class="stat-mode-btn ${state.statsMode===id?'active':''}" data-mode="${id}">${label}</button>`).join('')}</div>${targetControl}</div></div></div>`;const back=mobile&&state.analysisReturn?'<div class="analysis-back-row"><button class="btn ghost" onclick="backAnalysis()">戻る</button></div>':'';const head=statsHead(p,items,r,per);return `<div class="analysis-screen">${back}${filter}${head}${analysisShots(r,per)}<div class="card analysis-break-card">${analysisBreakdowns(r,per)}</div>${!items.length?'<div class="card"><p class="sub">該当データなし</p></div>':''}</div>`}
function filterItems(pid){const games=targetGames(),ids=new Set(games.map(g=>g.id)); return state.stats.filter(s=>s.playerId===pid&&ids.has(s.gameId)&&statHasRegisteredData(s,games.find(g=>g.id===s.gameId)))}
function removeDuplicateAnalysisGameCount(html){if(!['all','month','day','period'].includes(state.statsMode))return html;return html.replace(/<div class="analysis-date">\d+試合　(?=対象試合数：)/,'<div class="analysis-date">')}
function statsHead(p,items,r,per){const games=targetGames();if(state.statsMode==='game'){const g=state.games.find(x=>x.id===state.targetId);if(!g)return '<div class="card">対象データなし</div>';const s=gameStats(g.id,p?.id)||{};return `<div class="card analysis-info analysis-game-info"><div class="analysis-info-top"><div class="analysis-info-main"><div class="analysis-info-kicker">対象試合情報</div><div class="analysis-match-line"><span class="analysis-trophy">🏆</span><span>${g.tournament||'大会未登録'}　vs　${g.opponent||''}</span></div><div class="analysis-date">${g.date||''}　${g.quarters||0}Q</div>${detailStatsViewControl(g,s)}${detailUnregisteredNotice(g,s)}</div><div class="analysis-score">${scoreLine(g)}<div class="sub">${resultText(g)} ${resultWord(g)}</div></div></div><div class="analysis-game-basic"><div class="section-title">基本スタッツ</div>${analysisBasic(r,false)}</div></div>`}const enteredGames=gamesWithStats(games,p?.id),rec=gameRecord(enteredGames),totalQ=totalQForGames(enteredGames,p?.id);const labels={tournament:'対象大会情報',period:'対象期間情報',year:'対象年情報',month:'対象月情報',day:'対象日情報',all:'全期間情報'};const title={tournament:state.targetId||'対象大会なし',period:`${state.periodStart||'開始日未指定'} ～ ${state.periodEnd||'終了日未指定'}`,year:state.targetId||'対象年なし',month:state.targetId||'対象月なし',day:state.targetId||'対象日なし',all:'全期間'}[state.statsMode]||'対象データ';const listModes=['tournament','period','year','month','day','all'];const list=listModes.includes(state.statsMode)?`<div class="analysis-target-games"><div class="section-title">対象試合一覧</div>${analysisGameTable(enteredGames)}</div>`:'';const basicTitle='基本スタッツ（1試合4Q換算）';return `<div class="card analysis-info analysis-summary-info"><div class="analysis-info-top"><div class="analysis-info-main"><div class="analysis-info-kicker">${labels[state.statsMode]||'集計対象'}</div><div class="analysis-match-line"><span class="analysis-trophy">🏆</span><span>${title}</span></div><div class="analysis-date">${state.statsMode==='tournament'?dateRange(enteredGames):`${enteredGames.length}試合`}　対象試合数：${enteredGames.length}試合　総Q数：${totalQ}Q</div></div><div class="analysis-record"><div class="analysis-record-main">${rec.w}<span>勝</span>${rec.l}<span>敗</span>${rec.d}<span>分</span></div><div class="analysis-record-rate">勝率 ${rec.rate}%</div></div></div>${list}<div class="analysis-game-basic"><div class="section-title">${basicTitle}</div>${analysisBasic(r,true)}</div></div>`}
function mobileGameAnalysis(g,p,r,s={}){return `<div class="analysis-screen game-detail-analysis"><div class="analysis-back-row"><button class="btn ghost" onclick="goBackGames()">戻る</button>${state.user?`<button class="btn small" onclick="openGameForm('${g.id}')">修正</button>`:''}</div><div class="card"><label>個人スタッツ<select id="detailPlayer">${state.players.map(x=>`<option value="${x.id}" ${x.id===p?.id?'selected':''}>No.${x.number||''} ${x.name||''}</option>`).join('')}</select></label></div><div class="card analysis-info analysis-game-info"><div class="analysis-info-top"><div class="analysis-info-main"><div class="analysis-info-kicker">対象試合情報</div><div class="analysis-match-line"><span class="analysis-trophy">🏆</span><span>${g.tournament||'大会未登録'}　vs　${g.opponent||''}</span></div><div class="analysis-date">${g.date||''}　${g.quarters||0}Q${quarterStatusText(g,p?.id)}</div>${detailStatsViewControl(g,s)}${detailUnregisteredNotice(g,s)}</div><div class="analysis-score">${scoreLine(g)}<div class="sub">${resultText(g)} ${resultWord(g)}</div></div></div><div class="analysis-game-basic"><div class="section-title">基本スタッツ</div>${analysisBasic(r,false)}</div></div>${analysisShots(r,false)}<div class="card analysis-break-card">${analysisBreakdowns(r,false)}</div>${state.user?`<div class="card mobile-detail-actions"><div class="row"><button class="btn" onclick="openDetailStatsForm('${g.id}')">個人スタッツ修正</button><button class="btn danger" onclick="deletePlayerStats('${g.id}', '${p?.id||''}')">個人スタッツ削除</button></div></div>`:''}</div>`}
function gameDetailView(){const g=state.games.find(x=>x.id===state.selectedGameId); if(!g)return `<div class="card"><button class="btn ghost" onclick="goBackGames()">戻る</button><p class="sub">試合が見つかりません</p></div>`; let p=player(); const s=gameStats(g.id,p?.id)||{}; const r=sumStats(statForDetailView(g,s)); if(isMobileView())return mobileGameAnalysis(g,p,r,s); return `<div class="analysis-screen game-detail-analysis pc-detail-analysis"><div class="analysis-back-row"><button class="btn ghost" onclick="goBackGames()">戻る</button>${state.user?`<button class="btn small" onclick="openGameForm('${g.id}')">修正</button>`:''}</div><div class="card"><label>個人スタッツ<select id="detailPlayer">${state.players.map(x=>`<option value="${x.id}" ${x.id===p?.id?'selected':''}>No.${x.number||''} ${x.name||''}</option>`).join('')}</select></label></div><div class="card analysis-info analysis-game-info"><div class="analysis-info-top"><div class="analysis-info-main"><div class="analysis-info-kicker">対象試合情報</div><div class="analysis-match-line"><span class="analysis-trophy">🏆</span><span>${g.tournament||'大会未登録'}　vs　${g.opponent||''}</span></div><div class="analysis-date">${g.date||''}　${g.quarters||0}Q${quarterStatusText(g,p?.id)}</div>${detailStatsViewControl(g,s)}${detailUnregisteredNotice(g,s)}</div><div class="analysis-score">${scoreLine(g)}<div class="sub">${resultText(g)} ${resultWord(g)}</div></div></div><div class="analysis-game-basic"><div class="section-title">基本スタッツ</div>${analysisBasic(r,false)}</div></div>${analysisShots(r,false)}<div class="card analysis-break-card">${analysisBreakdowns(r,false)}</div>${state.user?`<div class="card mobile-detail-actions"><div class="row"><button class="btn" onclick="openDetailStatsForm('${g.id}')">個人スタッツ修正</button><button class="btn danger" onclick="deletePlayerStats('${g.id}', '${p?.id||''}')">個人スタッツ削除</button></div></div>`:''}</div>`}
window.openGameDetail=(id)=>{state.selectedGameId=id;if(!detailStatsViews()[id])setDetailStatsView(id,'game');state.tab='gameDetail';render()};
window.openDetailStatsForm=(id)=>{const g=state.games.find(x=>x.id===id);if(!g)return;const view=detailStatsView(g);if(getGameStatsRegistrationType(g)==='quarter'&&view==='game'){toast('Qを選択してからスタッツ入力してください');return}statsForm(id,view.startsWith('q')?num(view.replace('q','')):null)};
window.openAnalysisGame=(id)=>{if(!isMobileView())return;state.analysisReturn={statsMode:state.statsMode,targetId:state.targetId,categoryId:state.categoryId,periodStart:state.periodStart,periodEnd:state.periodEnd,scrollY:window.scrollY};state.statsMode='game';state.targetId=id;render();window.scrollTo(0,0)};
window.backAnalysis=()=>{const back=state.analysisReturn;if(!back)return;state.statsMode=back.statsMode;state.targetId=back.targetId;state.categoryId=back.categoryId;state.periodStart=back.periodStart;state.periodEnd=back.periodEnd;state.analysisReturn=null;render();requestAnimationFrame(()=>window.scrollTo(0,back.scrollY||0))};
window.deletePlayerStats=async(gameId,playerId)=>{if(!requireLogin())return;if(!playerId)return;if(confirm('この選手の個人スタッツを削除しますか？')){await deleteDoc(doc(db,'stats',`${gameId}_${playerId}`));toast('削除しました');render()}};
window.openHomePlayerSelect=()=>{if(!state.players.length){toast('選手データなし');return}modal(`<h2>対象選手を選択</h2><label>選手<select id="homePlayerChoice">${state.players.map(p=>`<option value="${p.id}" ${p.id===player()?.id?'selected':''}>No.${p.number||''} ${p.name||''}</option>`).join('')}</select></label><div class="row game-form-actions"><button class="btn" id="saveHomePlayer">選択</button><button class="btn ghost" id="closeModal">閉じる</button></div>`);$('#saveHomePlayer').onclick=()=>{state.lastPlayerId=$('#homePlayerChoice').value;setLastPlayerId(state.lastPlayerId);closeModal();render()};$('#closeModal').onclick=closeModal};
window.openTeamGame=(id)=>{state.teamReturn={teamMode:state.teamMode,teamTargetId:state.teamTargetId,scrollY:window.scrollY};state.teamMode='game';state.teamTargetId=id;setDetailStatsView(id,'game');render();window.scrollTo(0,0)};
window.backTeam=()=>{const back=state.teamReturn;if(!back)return;state.teamMode=back.teamMode;state.teamTargetId=back.teamTargetId;state.teamReturn=null;render();requestAnimationFrame(()=>window.scrollTo(0,back.scrollY||0))};
window.setTeamMonth=(changed='month')=>{const year=$('#teamMonthYear')?.value||'';let month=$('#teamMonthMonth')?.value||'';if(changed==='year'){const available=gamesWithStats(state.games).map(g=>(g.date||'').slice(0,7)).filter(value=>value.startsWith(`${year}-`)).sort().reverse();month=(available[0]||'').slice(5,7)}state.teamReturn=null;state.teamDetail=null;state.teamTargetId=year&&month?`${year}-${month}`:'';render()};
window.openTeamStatDetail=(type)=>{if(!isMobileView())return;state.teamDetail={type,scrollY:window.scrollY};history.pushState({r32TeamDetail:true},'');render();window.scrollTo(0,0)};
window.backTeamStatDetail=()=>{if(history.state?.r32TeamDetail){history.back();return}const y=state.teamDetail?.scrollY||0;state.teamDetail=null;render();requestAnimationFrame(()=>window.scrollTo(0,y))};
window.addEventListener('popstate',()=>{if(state.tab==='team'&&state.teamDetail){const y=state.teamDetail.scrollY||0;state.teamDetail=null;render();requestAnimationFrame(()=>window.scrollTo(0,y))}});

function teamTargetGames(){let games=state.games;if(state.teamMode==='tournament')games=games.filter(g=>g.tournament===state.teamTargetId);else if(state.teamMode==='day')games=filterGamesByDate(games,state.teamTargetId);else if(state.teamMode==='month')games=filterGamesByMonth(games,state.teamTargetId);else if(state.teamMode==='game')games=games.filter(g=>g.id===state.teamTargetId);return gamesWithStats(games)}
function teamRawStatsForGames(games){const ids=new Set(games.map(g=>g.id));return state.stats.filter(s=>ids.has(s.gameId)&&statHasRegisteredData(s,games.find(g=>g.id===s.gameId)))}
function teamStatsForGames(games){const items=teamRawStatsForGames(games);return state.teamMode==='game'&&games.length===1?statsForSelectedGameView(games[0],items):items}
function teamGameList(games){return `<div class="analysis-target-games"><div class="section-title">対象試合一覧</div><div class="analysis-game-list compact">${games.map(g=>`<button type="button" class="analysis-game-item" onclick="openTeamGame('${g.id}')"><div><b>${g.date||''}</b><span>${g.tournament||'大会未登録'}</span></div><div class="analysis-game-scoreline"><span>vs ${g.opponent||''}</span><b class="analysis-game-score">${scoreLine(g)}</b><em class="${resultClass(g)}">${resultWord(g)}</em></div></button>`).join('')||'<div class="analysis-game-item"><div><b>対象試合なし</b></div></div>'}</div></div>`}
function teamDetailType(type){return {pts:{kind:'value',title:'得点（PTS）',team:'チーム合計',col:'得点',value:s=>derived(s).pts,total:r=>derived(r).pts},ast:{kind:'value',title:'アシスト（AST）',team:'チーム合計',col:'アシスト',value:s=>s.ast,total:r=>r.ast},blk:{kind:'value',title:'ブロック（BLK）',team:'チーム合計',col:'ブロック',value:s=>s.blk,total:r=>r.blk},stl:{kind:'value',title:'スティール（STL）',team:'チーム合計',col:'スティール',value:s=>derived(s).stl,total:r=>derived(r).stl},reb:{kind:'value',title:'リバウンド（REB）',team:'チーム合計',col:'リバウンド',value:s=>derived(s).reb,total:r=>derived(r).reb},to:{kind:'value',title:'ターンオーバー（TO）',team:'チーム合計',col:'TO',value:s=>derived(s).to,total:r=>derived(r).to},two:{kind:'shot',title:'2ポイント 詳細',attempt:'2PA',made:'2PM',pct:'2P%',attemptValue:s=>s.twoPa,madeValue:s=>s.twoPm,totalAttempt:r=>r.twoPa,totalMade:r=>r.twoPm},three:{kind:'shot',title:'3ポイント 詳細',attempt:'3PA',made:'3PM',pct:'3P%',attemptValue:s=>s.threePa,madeValue:s=>s.threePm,totalAttempt:r=>r.threePa,totalMade:r=>r.threePm},fg:{kind:'shot',title:'フィールドゴール 詳細',attempt:'FGA',made:'FGM',pct:'FG%',attemptValue:s=>derived(s).fga,madeValue:s=>derived(s).fgm,totalAttempt:r=>derived(r).fga,totalMade:r=>derived(r).fgm},ft:{kind:'shot',title:'フリースロー 詳細',attempt:'FTA',made:'FTM',pct:'FT%',attemptValue:s=>s.fta,madeValue:s=>s.ftm,totalAttempt:r=>r.fta,totalMade:r=>r.ftm},passCut:{kind:'value',title:'PI（インターセプト）',team:'チーム合計',col:'PI',value:s=>s.passCut,total:r=>r.passCut},dribbleCut:{kind:'value',title:'DS（スティール）',team:'チーム合計',col:'DS',value:s=>s.dribbleCut,total:r=>r.dribbleCut},stealOther:{kind:'value',title:'OTH（その他STL）',team:'チーム合計',col:'OTH',value:s=>s.stealOther,total:r=>r.stealOther},or:{kind:'value',title:'OR（オフェンスリバウンド）',team:'チーム合計',col:'OR',value:s=>s.or,total:r=>r.or},dr:{kind:'value',title:'DR（ディフェンスリバウンド）',team:'チーム合計',col:'DR',value:s=>s.dr,total:r=>r.dr},passMiss:{kind:'value',title:'PM（パスミス）',team:'チーム合計',col:'PM',value:s=>s.passMiss,total:r=>r.passMiss},dribbleMiss:{kind:'value',title:'DM（ドリブルミス）',team:'チーム合計',col:'DM',value:s=>s.dribbleMiss,total:r=>r.dribbleMiss},catchMiss:{kind:'value',title:'CM（キャッチミス）',team:'チーム合計',col:'CM',value:s=>s.catchMiss,total:r=>r.catchMiss},violation:{kind:'value',title:'VIO（バイオレーション）',team:'チーム合計',col:'VIO',value:s=>s.violation,total:r=>r.violation},otherTo:{kind:'value',title:'OTH（その他TO）',team:'チーム合計',col:'OTH',value:s=>s.otherTo,total:r=>r.otherTo}}[type]}
function teamDetailRows(games,def){const items=teamStatsForGames(games),order=new Map(state.players.map((p,i)=>[p.id,i]));return state.players.map(p=>{const s=sumStats(items.filter(x=>x.playerId===p.id));if(def.kind==='shot'){const att=def.attemptValue(s),made=def.madeValue(s);return {player:p,att,made,pct:pct(made,att),key:att,html:`<div>${att}</div><div>${made}</div><div>${pct(made,att)}</div>`}}const value=def.value(s);return {player:p,value,key:value,html:`<div>${value}</div>`}}).filter(x=>x.key>0).sort((a,b)=>b.key-a.key||(order.get(a.player.id)??9999)-(order.get(b.player.id)??9999))}
function teamStatDetailView(){const type=state.teamDetail?.type,def=teamDetailType(type),games=teamTargetGames(),items=teamStatsForGames(games),r=sumStats(items),totalQ=totalQForGames(games);if(!def)return '';const rows=teamDetailRows(games,def),total=def.kind==='shot'?{att:def.totalAttempt(r),made:def.totalMade(r)}:{value:def.total(r)};const totalHtml=def.kind==='shot'?`<div><span>試投数</span><b>${total.att}</b></div><div><span>成功数</span><b>${total.made}</b></div><div><span>成功率</span><b>${pct(total.made,total.att)}</b></div>`:`<div><span>${def.team}</span><b>${total.value}</b></div>`;const head=def.kind==='shot'?`<div>#</div><div>選手名</div><div>${def.attempt}</div><div>${def.made}</div><div>${def.pct}</div>`:`<div>#</div><div>選手名</div><div>${def.col}</div>`;return `<div class="analysis-screen team-screen team-stat-detail"><div class="analysis-back-row"><button class="btn ghost team-detail-back" onclick="backTeamStatDetail()">戻る</button></div><div class="team-detail-title">${def.title}</div><div class="team-detail-meta">対象試合数：${games.length}試合 / ${totalQ}Q</div><div class="card team-detail-total">${totalHtml}</div><div class="team-detail-table ${def.kind==='shot'?'shot':'value'}"><div class="team-detail-row header">${head}</div>${rows.map((row,i)=>`<div class="team-detail-row"><div>${i+1}</div><div>#${row.player.number||''} ${row.player.name||''}</div>${row.html}</div>`).join('')||'<div class="team-detail-empty">該当する選手がいません</div>'}</div></div>`}
function teamTapAttr(type){return isMobileView()?` class="analysis-basic-card team-stat-tappable" role="button" tabindex="0" onclick="openTeamStatDetail('${type}')"`:' class="analysis-basic-card"'}
function teamAnalysisBasic(r){const d=derived(r);return `<div class="analysis-basic">${[['pts','PTS（ポイント）',d.pts],['ast','AST（アシスト）',r.ast],['blk','BLK（ブロック）',r.blk],['stl','STL（スティール）',d.stl],['reb','REB（OR+DR）',d.reb],['to','TO（ターンオーバー）',d.to]].map(([type,lab,val])=>`<div${teamTapAttr(type)}><span>${lab}</span><b>${statVal(val,1,false)}</b></div>`).join('')}</div>`}
function teamAnalysisShots(r){const d=derived(r),groups=[['two','2ポイント','2PA','2PM','2P%',r.twoPa,r.twoPm,pct(r.twoPm,r.twoPa)],['three','3ポイント','3PA','3PM','3P%',r.threePa,r.threePm,pct(r.threePm,r.threePa)],['fg','フィールドゴール','FGA','FGM','FG%',d.fga,d.fgm,pct(d.fgm,d.fga)],['ft','フリースロー','FTA','FTM','FT%',r.fta,r.ftm,pct(r.ftm,r.fta)]];return `<div class="card analysis-shot-card"><div class="section-title">シュート内訳</div><div class="analysis-shot-grid">${groups.map(([type,title,a,m,p,av,mv,pv])=>`<div class="analysis-shot ${isMobileView()?'team-stat-tappable':''}" ${isMobileView()?`role="button" tabindex="0" onclick="openTeamStatDetail('${type}')"`:''}><h3>${title}</h3><div class="analysis-shot-values"><div><span>${a}</span><b>${av}</b></div><div><span>${m}</span><b>${mv}</b></div><div class="pct"><span>${p}</span><b>${pv}</b></div></div></div>`).join('')}</div></div>`}
function teamAnalysisBreak(title,total,items,cls){return `<div class="analysis-break"><h3>${title}内訳</h3><div class="analysis-break-values ${cls}">${items.map(([type,short,long,val])=>`<div class="${isMobileView()?'team-stat-tappable':''}" ${isMobileView()?`role="button" tabindex="0" onclick="openTeamStatDetail('${type}')"`:''}><span>${short}</span><span>(${long})</span><b>${val}</b></div>`).join('')}</div><div class="analysis-break-total"><span>合計</span><b>${total}</b></div></div>`}
function teamAnalysisToBreakdown(r,d){const items=[['passMiss','PM','パスミス',r.passMiss],['dribbleMiss','DM','ドリブルミス',r.dribbleMiss],['catchMiss','CM','キャッチミス',r.catchMiss],['violation','VIO','バイオレーション',r.violation],['otherTo','OTH','その他',r.otherTo],['to','合計','',d.to]];return `<div class="analysis-break analysis-to-break"><h3>TO内訳</h3><div class="analysis-break-values cols6">${items.map(([type,short,long,val],i)=>`<div class="${i===5?'analysis-total-cell ':''}${isMobileView()?'team-stat-tappable':''}" ${isMobileView()?`role="button" tabindex="0" onclick="openTeamStatDetail('${type}')"`:''}><span>${short}</span>${long?`<span>(${long})</span>`:''}<b>${val}</b></div>`).join('')}</div></div>`}
function teamAnalysisBreakdowns(r){const d=derived(r);return `<div class="analysis-break-grid">${teamAnalysisBreak('STL',d.stl,[['passCut','PI','インターセプト',r.passCut],['dribbleCut','DS','スティール',r.dribbleCut],['stealOther','OTH','その他',r.stealOther]],'cols3')}${teamAnalysisBreak('REB',d.reb,[['or','OR','オフェンスリバウンド',r.or],['dr','DR','ディフェンスリバウンド',r.dr]],'cols2')}${teamAnalysisToBreakdown(r,d)}</div>`}
function teamView(){
  if(isMobileView()&&state.teamDetail)return teamStatDetailView();
  const eligibleGames=gamesWithStats(state.games);
  const tournaments=[...new Set(eligibleGames.map(g=>g.tournament).filter(Boolean))];
  const gameTargets=eligibleGames.map(g=>({id:g.id,label:`${g.date||''} vs ${g.opponent||''}`}));
  const tournamentTargets=tournaments.map(id=>({id,label:id}));
  const dayTargets=[...new Set(eligibleGames.map(g=>g.date).filter(Boolean))].sort().reverse().map(id=>({id,label:id}));
  const monthTargets=[...new Set(eligibleGames.map(g=>(g.date||'').slice(0,7)).filter(Boolean))].sort().reverse().map(id=>({id,label:id}));
  const targets={game:gameTargets,tournament:tournamentTargets,day:dayTargets,month:monthTargets}[state.teamMode]||[];
  const previousTarget=state.teamTargetId;
  if(state.teamMode==='all')state.teamTargetId='';
  else if(targets.length&&!targets.some(t=>t.id===state.teamTargetId))state.teamTargetId=targets[0].id;
  else if(!targets.length)state.teamTargetId='';
  if(state.teamMode==='game'&&state.teamTargetId&&state.teamTargetId!==previousTarget)setDetailStatsView(state.teamTargetId,'game');

  let targetControl='';
  if(['game','tournament'].includes(state.teamMode))targetControl=`<div class="analysis-target-row team-target-row"><label>対象選択<select id="teamTarget">${targets.map(t=>`<option value="${t.id}" ${t.id===state.teamTargetId?'selected':''}>${t.label}</option>`).join('')}</select></label></div>`;
  if(state.teamMode==='day')targetControl=`<div class="analysis-target-row team-target-row"><label>日付選択<input type="date" id="teamTarget" value="${state.teamTargetId||''}"></label></div>`;
  if(state.teamMode==='month'){
    const years=[...new Set(monthTargets.map(t=>t.id.slice(0,4)))];
    const year=(state.teamTargetId||monthTargets[0]?.id||'').slice(0,4);
    const months=monthTargets.filter(t=>t.id.startsWith(`${year}-`)).map(t=>t.id.slice(5,7));
    const month=(state.teamTargetId||monthTargets[0]?.id||'').slice(5,7)||months[0]||'';
    targetControl=`<div class="analysis-target-row team-target-row"><label>年選択<select id="teamMonthYear" onchange="setTeamMonth('year')">${years.map(x=>`<option value="${x}" ${x===year?'selected':''}>${x}</option>`).join('')}</select></label><label>月選択<select id="teamMonthMonth" onchange="setTeamMonth('month')">${months.map(x=>`<option value="${x}" ${x===month?'selected':''}>${x}</option>`).join('')}</select></label></div>`;
  }

  const games=teamTargetGames(),rawItems=teamRawStatsForGames(games),items=teamStatsForGames(games),r=sumStats(items),g=games[0],mobile=isMobileView();
  const modeTitle={all:'全期間',tournament:state.teamTargetId||'大会未選択',day:state.teamTargetId||'日付未選択',month:state.teamTargetId||'年月未選択'};
  const title=modeTitle[state.teamMode]||(g?`${g.tournament||'大会未登録'}　vs　${g.opponent||''}`:'試合未選択');
  const date=['all','tournament'].includes(state.teamMode)?dateRange(games):(state.teamMode==='game'?(g?.date||''):state.teamTargetId);
  const totalQ=totalQForGames(games),qInfo=state.teamMode==='game'?`対象試合数：${games.length}試合<span class="team-meta-line">Q数：${totalQ||num(g?.quarters)}Q</span>`:`対象試合数：${games.length}試合　総Q数：${totalQ}Q`;
  const rec=gameRecord(games),score=state.teamMode==='game'&&g?`<div class="analysis-score">${scoreLine(g)}<div class="sub">${resultText(g)} ${resultWord(g)}</div></div>`:`<div class="analysis-record"><div class="analysis-record-main">${rec.w}<span>勝</span>${rec.l}<span>敗</span>${rec.d}<span>分</span></div><div class="analysis-record-rate">勝率 ${rec.rate}%</div></div>`;
  const list=['tournament','all','day','month'].includes(state.teamMode)?teamGameList(games):'';
  const switcher=state.teamMode==='game'&&g?`${detailStatsViewControl(g,combinedQuarterStat(rawItems))}${detailUnregisteredNotice(g,combinedQuarterStat(rawItems))}`:'';
  const back=state.teamReturn?'<div class="analysis-back-row"><button class="btn ghost" onclick="backTeam()">戻る</button></div>':'';
  const kicker={all:'全期間',tournament:'対象大会',day:'対象日付',month:'対象年月',game:'対象試合'}[state.teamMode];
  const filter=state.teamReturn?'':`<div class="card analysis-filter-card team-filter-card"><div class="team-filter"><label>対象</label><div class="seg team-mode-seg">${[['game','試合'],['tournament','大会'],['all','全期間'],['day','日別'],['month','月別']].map(([id,label])=>`<button type="button" class="team-mode-btn ${state.teamMode===id?'active':''}" data-team-mode="${id}">${label}</button>`).join('')}</div>${targetControl}</div></div>`;
  return `<div class="analysis-screen team-screen">${back}<div class="analysis-title"><h2>チーム <small>TEAM</small></h2></div>${filter}<div class="card analysis-info analysis-summary-info"><div class="analysis-info-top"><div class="analysis-info-main"><div class="analysis-info-kicker">${kicker}</div><div class="analysis-match-line"><span class="analysis-trophy">🏆</span><span>${title}</span></div><div class="analysis-date">${date}</div><div class="analysis-date">${qInfo}</div>${switcher}</div>${score}</div>${list}<div class="analysis-game-basic"><div class="section-title">チーム合計スタッツ</div>${mobile?teamAnalysisBasic(r):analysisBasic(r,false)}</div></div>${mobile?teamAnalysisShots(r):analysisShots(r,false)}<div class="card analysis-break-card">${mobile?teamAnalysisBreakdowns(r):analysisBreakdowns(r,false)}</div>${!items.length?'<div class="card"><p class="sub">該当データなし</p></div>':''}</div>`;
}
function settingsView(){return `<div class="card"><h2>設定</h2><p class="sub">ログイン状態はログアウトするまで保持されます。端末のパスワード保存・自動入力に対応しています。</p><button class="btn ghost" onclick="location.reload()">再読み込み</button></div>`}
