function bind(){const lh=$('#loginHome'); if(lh)lh.onclick=loginModal; const lo=$('#logoutHome'); if(lo)lo.onclick=logout; const hps=$('#homePlayerSelect'); if(hps)hps.onclick=openHomePlayerSelect; document.querySelectorAll('.home-stats-mode-btn').forEach(b=>b.onclick=()=>{state.homeStatsMode=b.dataset.homeStatsMode;render()}); const gs=$('#toggleGameSort'); if(gs)gs.onclick=()=>{state.gameSortDirection=state.gameSortDirection==='asc'?'desc':'asc';setGameSortDirection(state.gameSortDirection);state.games=sortGamesByDateAndSameDateOrder(state.games);render()}; const ag=$('#addGame'),agm=$('#addGameMobile'),agh=$('#addGameHome'),aghp=$('#addGameHomePc'); [ag,agm,agh,aghp].filter(Boolean).forEach(b=>b.onclick=()=>gameForm()); const ap=$('#addPlayer'),apm=$('#addPlayerMobile'); [ap,apm].filter(Boolean).forEach(b=>b.onclick=()=>playerForm()); const sp=$('#statPlayer'); if(sp)sp.onchange=e=>{state.analysisReturn=null;state.lastPlayerId=e.target.value;setLastPlayerId(state.lastPlayerId);render()}; document.querySelectorAll('.stat-mode-btn').forEach(b=>b.onclick=()=>{state.analysisReturn=null;state.statsMode=b.dataset.mode;state.targetId='';render()}); document.querySelectorAll('.cat-btn').forEach(b=>b.onclick=()=>{state.analysisReturn=null;state.categoryId=b.dataset.category;state.targetId='';render()}); document.querySelectorAll('.team-mode-btn').forEach(b=>b.onclick=()=>{state.teamReturn=null;state.teamDetail=null;state.teamMode=b.dataset.teamMode;state.teamTargetId='';render()}); const tt=$('#teamTarget'); if(tt)tt.onchange=e=>{state.teamReturn=null;state.teamDetail=null;state.teamTargetId=e.target.value;setDetailStatsView(state.teamTargetId,'game');render()}; const sm=$('#statMode'); if(sm){sm.value=state.statsMode; sm.onchange=e=>{state.analysisReturn=null;state.statsMode=e.target.value;state.targetId='';render()}} const sc=$('#statCategory'); if(sc)sc.onchange=e=>{state.analysisReturn=null;state.categoryId=e.target.value;state.targetId='';render()}; const st=$('#statTarget'); if(st)st.onchange=e=>{state.analysisReturn=null;state.targetId=e.target.value;if(state.statsMode==='game')setDetailStatsView(state.targetId,'game');render()}; const my=$('#monthYear'),mm=$('#monthMonth'); if(my)my.onchange=e=>{state.analysisReturn=null;state.targetId=`${e.target.value}-${mm?.value||'01'}`;render()}; if(mm)mm.onchange=e=>{state.analysisReturn=null;state.targetId=`${my?.value||''}-${e.target.value}`;render()}; const ps=$('#periodStart'); if(ps)ps.onchange=e=>{state.analysisReturn=null;state.periodStart=e.target.value;render()}; const pe=$('#periodEnd'); if(pe)pe.onchange=e=>{state.analysisReturn=null;state.periodEnd=e.target.value;render()}; const dp=$('#detailPlayer'); if(dp)dp.onchange=e=>{state.lastPlayerId=e.target.value;setLastPlayerId(state.lastPlayerId);render()}; document.querySelectorAll('.detail-stat-view-btn').forEach(b=>b.onclick=()=>{setDetailStatsView(b.dataset.detailGame||state.selectedGameId,b.dataset.detailView);render()}); bindGameSorting();bindPlayerSorting();bindNumberSteppers()}

function bindGameSorting(){
  if(!state.user) return;
  const items=[...document.querySelectorAll('.game-sort-item')];
  items.forEach(item=>{
    const handle=item.querySelector('.game-sort-handle');
    if(handle){bindSortHandle(handle,item,'.game-sort-item',saveGameOrderFromDom,canMoveWithinSameGameDate)}
    item.addEventListener('dragover',e=>{e.preventDefault();const dragging=document.querySelector('.game-sort-item.dragging');if(!dragging||dragging===item||!canMoveWithinSameGameDate(dragging,item))return;const rect=item.getBoundingClientRect();const after=(e.clientY-rect.top)>rect.height/2;item.parentNode.insertBefore(dragging,after?item.nextSibling:item)});
  });
}
function gameById(id){return state.games.find(g=>g.id===id)}
function sameGameDate(a,b){return normalizeGameDate(a?.date||a?.gameDate)===normalizeGameDate(b?.date||b?.gameDate)}
function canMoveWithinSameGameDate(sourceEl,targetEl){return sameGameDate(gameById(sourceEl?.dataset?.gameId),gameById(targetEl?.dataset?.gameId))}
async function saveGameOrderFromDom(){
  if(!state.user) return;
  const groups=new Map();
  [...document.querySelectorAll('.game-sort-item')].forEach(el=>{const g=gameById(el.dataset.gameId);if(!g)return;const date=normalizeGameDate(g.date||g.gameDate);if(!groups.has(date))groups.set(date,[]);groups.get(date).push(g.id)});
  for(const ids of groups.values()) for(let i=0;i<ids.length;i++) await setDoc(doc(db,'games',ids[i]),{sameDateOrder:i,updatedAt:serverTimestamp()},{merge:true});
  toast('並び順を保存しました');
}
async function saveSameDateOrdersForDate(date,{promotedGame=null,excludeId=''}={}){
  const key=normalizeGameDate(date);if(!key)return;
  const base=sortGamesByDateAndSameDateOrder(state.games.filter(g=>normalizeGameDate(g.date||g.gameDate)===key&&g.id!==excludeId&&g.id!==promotedGame?.id),'asc');
  const ordered=promotedGame?[promotedGame,...base]:base;
  for(let i=0;i<ordered.length;i++) await setDoc(doc(db,'games',ordered[i].id),{sameDateOrder:i,updatedAt:serverTimestamp()},{merge:true});
}
let activeSort=null, sortPressTimer=null;
function sortPoint(e){const t=e.touches?.[0]||e.changedTouches?.[0]||e;return{clientX:t.clientX,clientY:t.clientY}}
function bindSortHandle(handle,item,itemSelector,saveOrder,canMove){
  handle.addEventListener('contextmenu',e=>{e.preventDefault();e.stopPropagation()});
  handle.addEventListener('click',e=>{e.preventDefault();e.stopPropagation()});
  handle.addEventListener('pointerdown',e=>scheduleHandleSort(handle,item,itemSelector,saveOrder,e,canMove),{passive:false});
  handle.addEventListener('touchstart',e=>scheduleHandleSort(handle,item,itemSelector,saveOrder,e,canMove),{passive:false});
  handle.addEventListener('dragstart',e=>{e.preventDefault();e.stopPropagation()});
}
function scheduleHandleSort(handle,item,itemSelector,saveOrder,e,canMove){
  e.preventDefault();e.stopPropagation();if(activeSort||sortPressTimer)return;
  const startEvent=e;
  const clear=ev=>{if(ev){ev.preventDefault();ev.stopPropagation()}clearTimeout(sortPressTimer);sortPressTimer=null;document.removeEventListener('pointerup',clear);document.removeEventListener('touchend',clear);document.removeEventListener('touchcancel',clear)};
  sortPressTimer=setTimeout(()=>{document.removeEventListener('pointerup',clear);document.removeEventListener('touchend',clear);document.removeEventListener('touchcancel',clear);sortPressTimer=null;startHandleSort(handle,item,itemSelector,saveOrder,startEvent,canMove)},180);
  document.addEventListener('pointerup',clear,{passive:false});
  document.addEventListener('touchend',clear,{passive:false});
  document.addEventListener('touchcancel',clear,{passive:false});
}
function startHandleSort(handle,item,itemSelector,saveOrder,e,canMove){
  e.preventDefault();e.stopPropagation();if(activeSort)return;
  activeSort={item,itemSelector,saveOrder};item.classList.add('dragging');
  const move=ev=>{if(!activeSort)return;ev.preventDefault();const p=sortPoint(ev);const target=[...document.querySelectorAll(itemSelector)].find(el=>{const r=el.getBoundingClientRect();return p.clientY>=r.top&&p.clientY<=r.bottom});if(!target||target===item||(canMove&&!canMove(item,target)))return;const rect=target.getBoundingClientRect();const after=(p.clientY-rect.top)>rect.height/2;target.parentNode.insertBefore(item,after?target.nextSibling:target)};
  const end=ev=>{if(ev){ev.preventDefault();ev.stopPropagation()}document.removeEventListener('pointermove',move);document.removeEventListener('pointerup',end);document.removeEventListener('touchmove',move);document.removeEventListener('touchend',end);document.removeEventListener('touchcancel',end);item.classList.remove('dragging');const done=activeSort;activeSort=null;done.saveOrder()};
  document.addEventListener('pointermove',move,{passive:false});document.addEventListener('pointerup',end,{passive:false});document.addEventListener('touchmove',move,{passive:false});document.addEventListener('touchend',end,{passive:false});document.addEventListener('touchcancel',end,{passive:false});
}
function bindPlayerSorting(){
  if(!state.user) return;
  const items=[...document.querySelectorAll('.player-sort-item')];
  items.forEach(item=>{
    const handle=item.querySelector('.player-sort-handle');
    if(handle){bindSortHandle(handle,item,'.player-sort-item',savePlayerOrderFromDom)}
    item.addEventListener('dragover',e=>{e.preventDefault();const dragging=document.querySelector('.player-sort-item.dragging');if(!dragging||dragging===item)return;const rect=item.getBoundingClientRect();const after=(e.clientY-rect.top)>rect.height/2;item.parentNode.insertBefore(dragging,after?item.nextSibling:item)});
  });
}
async function savePlayerOrderFromDom(){
  if(!state.user) return;
  const ids=[...document.querySelectorAll('.player-sort-item')].map(el=>el.dataset.playerId).filter(Boolean);
  for(let i=0;i<ids.length;i++) await setDoc(doc(db,'players',ids[i]),{sortOrder:i,updatedAt:serverTimestamp()},{merge:true});
  toast('並び順を保存しました');
}
function bindNumberSteppers(){
  document.querySelectorAll('[data-step-for]').forEach(b=>b.onclick=e=>{e.preventDefault();const input=$('#'+b.dataset.stepFor);if(!input)return;input.value=Math.max(0,num(input.value)+Number(b.dataset.delta));input.dispatchEvent(new Event('input',{bubbles:true}))});
}
function setupStatsDirty(base){
  const refresh=input=>{
    const label=input.closest('label');
    if(!label)return;
    label.classList.toggle('stat-dirty',num(input.value)!==num(base[input.id]));
  };
  Object.keys(base).forEach(id=>{
    const input=$('#'+id);
    if(!input)return;
    input.oninput=()=>refresh(input);
    refresh(input);
  });
}

