function playerForm(p={}){if(!requireLogin())return;const currentCategory=playerCategory(p);const categoryOptions=PLAYER_CATEGORIES.map(c=>`<option value="${c}" ${c===currentCategory?'selected':''}>${c}</option>`).join('');modal(`<h2>${p.id?'選手修正':'選手登録'}</h2><div class="form-grid"><label>名前<input id="pName" value="${p.name||''}"></label><label>背番号<input id="pNum" value="${p.number||''}"></label><label>カテゴリー<select id="pCategory">${categoryOptions}</select></label><label>ポジション<input id="pPos" value="${p.position||''}"></label></div><div class="row game-form-actions"><button class="btn" id="savePlayer">保存</button><button class="btn ghost" id="closeModal">閉じる</button>${p.id?'<button class="btn danger delete-right" id="deletePlayerFromEdit">削除</button>':''}</div>`);$('#savePlayer').onclick=async()=>{const id=p.id||uid();await setDoc(doc(db,'players',id),{name:$('#pName').value,number:$('#pNum').value,category:$('#pCategory').value,position:$('#pPos').value,sortOrder:p.sortOrder??state.players.length,updatedAt:serverTimestamp()},{merge:true});closeModal();toast('保存しました')};$('#closeModal').onclick=closeModal;const del=$('#deletePlayerFromEdit');if(del)del.onclick=async()=>{if(confirm('この選手を削除しますか？')){await deletePlayerById(p.id);closeModal();toast('削除しました');render()}}}
window.goBackGames=()=>{state.tab='games';state.selectedGameId='';render()};
window.openGameForm=(id)=>{const g=state.games.find(x=>x.id===id); if(g) gameForm(g)};
window.openStatsForm=(gameId)=>statsForm(gameId);
window.gameActions=(id)=>{const g=state.games.find(x=>x.id===id);modal(`<h2>vs ${g.opponent||''}</h2><p class="sub">${g.date||''} ${g.tournament||''} ${resultMark(g)} ${scoreLine(g).replace(" - ","-")}</p><div class="grid"><button class="btn" id="statsReg">スタッツ登録</button><button class="btn ghost" id="editGame">試合修正</button><button class="btn danger" id="delGame">試合削除</button><button class="btn ghost" id="closeModal">閉じる</button></div>`);$('#statsReg').onclick=()=>statsForm(id);$('#editGame').onclick=()=>{closeModal();gameForm(g)};$('#delGame').onclick=async()=>{if(!requireLogin())return;if(confirm('この試合と関連スタッツを削除しますか？')){const oldDate=g?.date||'';await deleteDoc(doc(db,'games',id));for(const s of state.stats.filter(x=>x.gameId===id)) await deleteDoc(doc(db,'stats',s.id));await saveSameDateOrdersForDate(oldDate,{excludeId:id});closeModal();toast('削除しました')}};$('#closeModal').onclick=closeModal}
function scoreInput(id,value){
  const v=value===undefined||value===null?'':num(value);
  return `<div class="num-wrap"><input type="number" min="0" id="${id}" value="${v}"><div class="num-steps"><button type="button" data-step-for="${id}" data-delta="1">▲</button><button type="button" data-step-for="${id}" data-delta="-1">▼</button></div></div>`;
}

function gameQuarterScoreFields(g={}){
  const qCount=Math.max(1,num($('#gQ')?.value||g.quarters||4));
  const scores=g.quarterScores||{};
  return Array.from({length:qCount},(_,i)=>{
    const q=i+1,score=scores[quarterScoreKey(q)]||{};
    return `<div class="quarter-score-row"><div class="sub">${q}Q終了時スコア</div><label>自チーム${scoreInput(`qTeam${q}`,score.team)}</label><label>相手${scoreInput(`qOpp${q}`,score.opponent)}</label></div>`;
  }).join('');
}

function collectQuarterScores(qCount){
  const quarterScores={},previous={team:0,opponent:0};
  let hasScores=false,finalScore=null,lastBase={...previous};
  for(let q=1;q<=qCount;q++){
    const teamRaw=$(`#qTeam${q}`)?.value??'',oppRaw=$(`#qOpp${q}`)?.value??'';
    if(teamRaw===''&&oppRaw==='')continue;
    if(teamRaw===''||oppRaw===''){toast(`${q}Q終了時スコアは自チームと相手の両方を入力してください`);return null}
    const current={team:num(teamRaw),opponent:num(oppRaw)};
    if(current.team<lastBase.team||current.opponent<lastBase.opponent){toast(`${q}Q終了時のスコアは、直前Q終了時のスコア以上を入力してください`);return null}
    quarterScores[quarterScoreKey(q)]=current;
    lastBase=current;
    finalScore=current;
    hasScores=true;
  }
  return {quarterScores:hasScores?quarterScores:null,finalScore};
}

function syncFinalScoreInputsFromQuarters(){
  const qCount=Math.max(1,num($('#gQ')?.value||4));
  let last=null;
  for(let q=1;q<=qCount;q++){
    const teamRaw=$(`#qTeam${q}`)?.value??'',oppRaw=$(`#qOpp${q}`)?.value??'';
    if(teamRaw!==''&&oppRaw!=='')last={team:num(teamRaw),opponent:num(oppRaw)};
  }
  if(last){const own=$('#gOwn'),opp=$('#gOppScore');if(own)own.value=last.team;if(opp)opp.value=last.opponent}
}

function gameForm(g={}){
  if(!requireLogin())return;
  const currentType=getGameStatsRegistrationType(g);
  modal(`<h2>${g.id?'試合修正':'試合登録'}</h2><div class="form-grid game-form-grid"><label>年月日<input type="date" id="gDate" value="${g.date||''}"></label><label>Q数${numInput('gQ',g.quarters||4)}</label><label>カテゴリー<input id="gCategory" list="categoryList" value="${g.category||''}"><datalist id="categoryList"><option value="U15"><option value="U14"><option value="中学"><option value="高校"><option value="練習"></datalist></label><label>大会名<input id="gTour" value="${g.tournament||''}"></label><label>対戦相手<input id="gOpp" value="${g.opponent||''}"></label><label>自チーム得点${numInput('gOwn',g.ownScore||0)}</label><label>相手得点${numInput('gOppScore',g.oppScore||0)}</label></div><div class="card"><div class="section-title">スタッツ登録方式</div><div class="seg stats-type-seg"><button type="button" class="stats-type-btn ${currentType==='game'?'active':''}" data-stats-type="game">試合登録</button><button type="button" class="stats-type-btn ${currentType==='quarter'?'active':''}" data-stats-type="quarter">Q登録</button></div></div><div class="card"><div class="section-title">Q別スコア（累積）</div><div id="quarterScoreFields">${gameQuarterScoreFields(g)}</div></div><div class="row game-form-actions"><button class="btn" id="saveGame">保存</button><button class="btn ghost" id="closeModal">閉じる</button>${g.id?'<button class="btn danger delete-right" id="deleteGameFromEdit">削除</button>':''}</div>`);
  let selectedType=currentType;
  const refreshType=()=>document.querySelectorAll('.stats-type-btn').forEach(b=>b.classList.toggle('active',b.dataset.statsType===selectedType));
  const refreshQuarterScores=()=>{$('#quarterScoreFields').innerHTML=gameQuarterScoreFields(g);bindNumberSteppers();document.querySelectorAll('#quarterScoreFields input').forEach(i=>i.oninput=syncFinalScoreInputsFromQuarters)};
  bindNumberSteppers();
  document.querySelectorAll('.stats-type-btn').forEach(b=>b.onclick=()=>{selectedType=b.dataset.statsType;refreshType()});
  const qInput=$('#gQ');if(qInput)qInput.oninput=refreshQuarterScores;
  document.querySelectorAll('[data-step-for="gQ"]').forEach(b=>b.addEventListener('click',()=>setTimeout(refreshQuarterScores,0)));
  document.querySelectorAll('#quarterScoreFields input').forEach(i=>i.oninput=syncFinalScoreInputsFromQuarters);
  $('#saveGame').onclick=async()=>{
    const id=g.id||uid(),oldDate=g.date||'',newDate=$('#gDate').value,shouldPromote=!g.id||normalizeGameDate(oldDate)!==normalizeGameDate(newDate);
    const oldType=getGameStatsRegistrationType(g);
    const hasStats=g.id&&state.stats.some(s=>s.gameId===g.id&&statHasRegisteredData(s,g));
    if(hasStats&&oldType!==selectedType){
      const message=oldType==='game'?'この試合には試合単位のスタッツが登録されています。Q登録へ変更すると、既存の試合スタッツはQ別スタッツとして自動変換されません。登録方式を変更しますか？':'この試合にはQごとのスタッツが登録されています。試合登録へ変更すると、Q別スタッツとの重複や未使用データが発生する可能性があります。登録方式を変更しますか？';
      if(!confirm(message))return;
    }
    const qCount=Math.max(1,num($('#gQ').value));
    const scoreData=collectQuarterScores(qCount);if(!scoreData)return;
    const finalScore=scoreData.finalScore||{team:num($('#gOwn').value),opponent:num($('#gOppScore').value)};
    const data={date:newDate,quarters:qCount,quarterCount:qCount,statsRegistrationType:selectedType,category:$('#gCategory').value,tournament:$('#gTour').value,opponent:$('#gOpp').value,ownScore:finalScore.team,oppScore:finalScore.opponent,finalScore:{team:finalScore.team,opponent:finalScore.opponent},sameDateOrder:shouldPromote?0:sameDateOrderValue(g),updatedAt:serverTimestamp()};
    if(scoreData.quarterScores)data.quarterScores=scoreData.quarterScores;
    if(!g.id)data.createdAt=serverTimestamp();
    await setDoc(doc(db,'games',id),data,{merge:true});
    if(shouldPromote){await saveSameDateOrdersForDate(oldDate,{excludeId:id});await saveSameDateOrdersForDate(newDate,{promotedGame:{id,...data}})}
    closeModal();toast('保存しました')
  };
  $('#closeModal').onclick=closeModal;
  const del=$('#deleteGameFromEdit');
  if(del)del.onclick=async()=>{if(!requireLogin())return;if(confirm('この試合と関連スタッツを削除しますか？')){const oldDate=g.date||'';await deleteDoc(doc(db,'games',g.id));for(const s of state.stats.filter(x=>x.gameId===g.id)) await deleteDoc(doc(db,'stats',s.id));await saveSameDateOrdersForDate(oldDate,{excludeId:g.id});closeModal();state.tab='games';state.selectedGameId='';toast('削除しました');render()}};
}

function statsForm(gameId,forcedQuarter=null){
  if(!requireLogin())return;
  const g=state.games.find(x=>x.id===gameId);
  const keys=STAT_KEYS,mode=getGameStatsRegistrationType(g);
  const existingForGame=state.stats.filter(x=>x.gameId===gameId);
  let defaultPid=state.lastPlayerId||'';
  if(defaultPid&&!state.players.some(p=>p.id===defaultPid))defaultPid='';
  if(!defaultPid&&existingForGame[0])defaultPid=existingForGame[0].playerId;
  if(!defaultPid&&state.players[0])defaultPid=state.players[0].id;
  const qCount=Math.max(1,num(g?.quarters||4));
  const currentView=detailStatsView(g);
  let selectedQuarter=forcedQuarter?Math.min(qCount,Math.max(1,num(forcedQuarter))):(currentView.startsWith('q')?Math.min(qCount,Math.max(1,num(currentView.replace('q','')))):1);
  const statForPlayer=()=>state.stats.find(x=>x.gameId===gameId&&x.playerId===$('#sfPlayer')?.value)||{};
  const inputGrid=(s={})=>`<div class="form-grid stats-form-grid"><label>2PA${numInput('twoPa',s.twoPa)}</label><label>2PM${numInput('twoPm',s.twoPm)}</label><label>3PA${numInput('threePa',s.threePa)}</label><label>3PM${numInput('threePm',s.threePm)}</label><label>FTA${numInput('fta',s.fta)}</label><label>FTM${numInput('ftm',s.ftm)}</label><label>AST${numInput('ast',s.ast)}</label><label>BLK${numInput('blk',s.blk)}</label><label>パスカット${numInput('passCut',s.passCut)}</label><label>ドリブルカット${numInput('dribbleCut',s.dribbleCut)}</label><label class="wide-mobile">その他STL${numInput('stealOther',s.stealOther)}</label><label class="mobile-row-start">OR${numInput('or',s.or)}</label><label>DR${numInput('dr',s.dr)}</label><label class="mobile-row-start">パスミス${numInput('passMiss',s.passMiss)}</label><label>ドリブルミス${numInput('dribbleMiss',s.dribbleMiss)}</label><label class="mobile-row-start">キャッチミス${numInput('catchMiss',s.catchMiss)}</label><label>バイオレーション${numInput('violation',s.violation)}</label><label class="wide-mobile">その他TO${numInput('otherTo',s.otherTo)}</label></div>`;
  const targetLabel=mode==='quarter'?`${selectedQuarter}Q スタッツ入力`:'試合スタッツ入力';
  modal(`<h2>${targetLabel}</h2><p class="sub">${g?`vs ${g.opponent||''}｜${g.date||''}｜${g.tournament||''}`:''}</p><p class="sub stats-target-note">対象：${mode==='quarter'?`${selectedQuarter}Q`:'試合'}</p><label>選手<select id="sfPlayer">${state.players.map(p=>`<option value="${p.id}" ${p.id===defaultPid?'selected':''}>No.${p.number||''} ${p.name||''}</option>`).join('')}</select></label><div id="sfBody"></div><div class="row game-form-actions stats-form-actions"><button class="btn" id="saveStats">保存</button><button class="btn ghost" id="closeModal">閉じる</button>${mode==='quarter'?'<button type="button" class="btn danger delete-right hidden" id="deleteQuarterStats">このQを削除</button>':''}</div>`);
  const renderInputs=()=>{
    const s=statForPlayer(),q=selectedQuarter,source=mode==='quarter'?(s.quarters?.[quarterKey(q)]||{}):s,base={};
    keys.forEach(k=>base[k]=num(source[k]));
    const registered=registeredQuarterNumbers(s);
    $('#sfBody').innerHTML=inputGrid(source);
    bindNumberSteppers();setupStatsDirty(base);
    const del=$('#deleteQuarterStats');
    const hasSavedQuarter=mode==='quarter'&&registered.includes(q);
    if(del){
      del.classList.toggle('hidden',!hasSavedQuarter);
      del.onclick=async()=>{const pid=$('#sfPlayer').value,id=`${gameId}_${pid}`,qNum=String(selectedQuarter),qk=quarterKey(qNum);if(!confirm(`この選手の${qNum}Qのスタッツを削除しますか？\nこの操作は元に戻せません。`))return;await setDoc(doc(db,'stats',id),{gameId,playerId:pid,quarters:{[qk]:null},updatedAt:serverTimestamp()},{merge:true});const current=statForPlayer();if(current.quarters)current.quarters[qk]=null;toast('削除しました');renderInputs()};
    }
  };
  const load=()=>{const pid=$('#sfPlayer').value;state.lastPlayerId=pid;setLastPlayerId(pid);renderInputs()};
  $('#sfPlayer').onchange=load;load();
  $('#saveStats').onclick=async()=>{const pid=$('#sfPlayer').value,id=`${gameId}_${pid}`,data={gameId,playerId:pid,updatedAt:serverTimestamp()};if(mode==='quarter'){const q=selectedQuarter,qData={registered:true,quarter:q};keys.forEach(k=>qData[k]=num($('#'+k).value));data.quarters={[quarterKey(q)]:qData};setDetailStatsView(gameId,`q${q}`)}else{data.quarters=g?.quarters||4;keys.forEach(k=>data[k]=num($('#'+k).value))}await setDoc(doc(db,'stats',id),data,{merge:true});state.lastPlayerId=pid;setLastPlayerId(pid);closeModal();toast('保存しました')};
  $('#closeModal').onclick=closeModal;
}
render();


